request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?gw ?gwName ?gwDir ?flow ?flowName ?sourceOrTarget WHERE {
  ?choreo a bboExt:Choreography .
  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .
  ?model tai:originalId ?origId .
  FILTER(CONTAINS(STR(?origId), "5a8e825c3a9a4049b67ab53c2ba7abc8"))
  ?gw a bboExt:ParallelGateway .
  ?gw bbo:name ?gwName .
  OPTIONAL { ?gw bboExt:gatewayDirection ?gwDir . }
  OPTIONAL {
    { ?flow bbo:has_sourceRef ?gw . BIND("target" AS ?sourceOrTarget) }
    UNION
    { ?flow bbo:has_targetRef ?gw . BIND("source" AS ?sourceOrTarget) }
  }
  ?flow bbo:name ?flowName .
}
LIMIT 50
